import{_ as s,o as a,c as p,e}from"./app-d7dec363.js";const t="/study-notes/assets/矩阵拼接-3b5736a7.jpg",o="/study-notes/assets/repmat-2bb80ddf.jpg",c="/study-notes/assets/rebuild-bda79b9a.jpg",l={};function i(u,n){return a(),p("div",null,n[0]||(n[0]=[e(`<h2 id="注释" tabindex="-1"><a class="header-anchor" href="#注释" aria-hidden="true">#</a> 注释</h2><p>快捷键 <code>ctrl + r</code></p><p>取消注释 <code>ctrl + t</code></p><p>两个 %% 即可实现分节，按住 ctrl 和上下键可以实现跳转</p><p><code>ctrl + enter</code> 只运行当前小节的代码</p><h2 id="变量" tabindex="-1"><a class="header-anchor" href="#变量" aria-hidden="true">#</a> 变量</h2><p>命名必须以字母开头</p><p><code>iskeyword</code> 获取关键字的完整列表</p><p>MATLAB 定义了一些比较特殊的变量：</p><ul><li><code>ans</code> 系统默认的保存运算结果的变量名</li><li><code>pi</code> 圆周率 Π</li><li><code>inf / -inf</code> 无穷大和负无穷大，注意 1 / 0 = inf</li><li><code>NaN</code> 不定值或缺失值，例如 0 / 0 或者 0 * inf 会返回 NaN</li><li><code>i 和 j</code> 复数中的虚数单位，例如 3 + 4i 和 3 + 4j 表示同一个复数</li><li><code>eps</code> 浮点相对精度。可以简单地将 eps 看作一个非常小的数，这个数大约等于 2.22e-16， 0 / (0 + eps) = 0</li></ul><p>设置 MATLAB 的数值显示方式：</p><ul><li><p>format long g 也可以写成 format longG</p></li><li><p><code>doc format</code> 查看 format 的帮助文档</p></li></ul><div class="custom-container tip"><p class="custom-container-title">小技巧</p><p><code>clc</code> 可以清空命令行窗口；<code>clear</code> 清空工作区</p><p>一些计算结果不需要在命令行显示，可以在代码的最后加上英文分号</p><p>两行代码放在同一行，也用分号分隔开</p></div><h2 id="常见的数学运算函数" tabindex="-1"><a class="header-anchor" href="#常见的数学运算函数" aria-hidden="true">#</a> 常见的数学运算函数</h2><ul><li><p><code>+ - * / ^</code></p></li><li><p><code>abs(数值)</code> 求绝对值、复数的模长</p></li><li><p><code>floor(数值)</code> 朝负无穷大截取整数</p></li><li><p><code>fix(数值)</code> 朝 0 截取整数</p></li><li><p><code>ceil(数值)</code> 朝正无穷大截取整数</p></li><li><p><code>round(X, [N])</code> 将 X 在第 N 位数四舍五入</p><ul><li>N &gt; 0，四舍五入到小数点右侧的第 N 位数</li><li>N = 0，四舍五入到最接近的整数</li><li>N &lt; 0，四舍五入到小数点左侧的第 N 位数</li></ul></li><li><p><code>mod(a, m)</code>，a 除以 m 后的余数</p></li><li><p><code>sqrt(a)</code>，计算 a 的平方根，可以为负数</p></li><li><p><code>exp(a)</code>，自然常数 e 的 a 次方</p></li><li><p><code>log(a)</code>，自然常数 e 为底的对数</p></li><li><p><code>log2(a)</code>、<code>log10(a)</code>，分别计算以 2、10 为底的对数</p></li></ul><h2 id="矩阵" tabindex="-1"><a class="header-anchor" href="#矩阵" aria-hidden="true">#</a> 矩阵</h2><p>向量 --&gt; 一维数组，矩阵 --&gt; 二维数组</p><h3 id="向量" tabindex="-1"><a class="header-anchor" href="#向量" aria-hidden="true">#</a> 向量</h3><h4 id="创建向量" tabindex="-1"><a class="header-anchor" href="#创建向量" aria-hidden="true">#</a> 创建向量</h4><ol><li>直接输入法</li></ol><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code><span class="token comment">% 行向量</span>
a <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span>
b <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span> <span class="token number">2</span> <span class="token number">3</span><span class="token punctuation">]</span>

<span class="token comment">% 列向量</span>
c <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">]</span>
d <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span>
    <span class="token number">2</span>
    <span class="token number">3</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>冒号法</li></ol><p><code>A:step:B</code>，A 是起始值，step 是每次递增或递减的步长，B 是终止值（不一定刚好停在这里，&lt;= B）；若 step = 1，则可简写为 A:B</p><ol start="3"><li>利用 MATLAB 函数创建</li></ol><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code><span class="token comment">% 等差数列</span>
<span class="token comment">% linspace(a, b, [n])，创建一个行向量，第一个元素为 a，最后一个元素为 b，形成总数为 n（默认为 100） 个元素的线性间隔的向量</span>

<span class="token comment">% 等比数列</span>
<span class="token comment">% logspace(a, b, [n])，创建一个行向量，第一个元素为 10^a，最后一个元素为 10^b，形成总数为 n（默认为 50）个元素的等比向量</span>
a <span class="token operator">=</span> <span class="token function">logspace</span><span class="token punctuation">(</span><span class="token function">log10</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token function">log10</span><span class="token punctuation">(</span><span class="token number">1024</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="向量元素的引用" tabindex="-1"><a class="header-anchor" href="#向量元素的引用" aria-hidden="true">#</a> 向量元素的引用</h4><p>length 或者 numel 函数都可以计算向量中包含的元素个数</p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>a <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">8</span><span class="token punctuation">,</span> <span class="token number">9</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
b1 <span class="token operator">=</span> <span class="token function">length</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span>
b2 <span class="token operator">=</span> <span class="token function">numel</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="custom-container warning"><p class="custom-container-title">注意</p><p>MATLAB 中，数组的索引是从 1 开始的</p></div><ol><li>单个元素的引用</li></ol><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>a <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">8</span><span class="token punctuation">,</span> <span class="token number">9</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">]</span><span class="token punctuation">;</span>

<span class="token comment">% a(ind)，超出范围会报错</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>多个元素引用</li></ol><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code><span class="token comment">% ind 可以是一个索引数组</span>
a <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">8</span><span class="token punctuation">,</span> <span class="token number">9</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
ind <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
b1 <span class="token operator">=</span> <span class="token function">a</span><span class="token punctuation">(</span>ind<span class="token punctuation">)</span>

<span class="token comment">% end 关键字表示数组最后一个元素的索引，end 还可以用于计算</span>
b2 <span class="token operator">=</span> <span class="token function">a</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token operator">:</span> <span class="token keyword">end</span><span class="token punctuation">)</span>
b3 <span class="token operator">=</span> <span class="token function">a</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token operator">:</span> <span class="token keyword">end</span> <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="向量元素的修改和删除" tabindex="-1"><a class="header-anchor" href="#向量元素的修改和删除" aria-hidden="true">#</a> 向量元素的修改和删除</h4><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code><span class="token comment">% 修改</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">4</span><span class="token punctuation">;</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">50</span><span class="token punctuation">,</span> <span class="token number">60</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token operator">:</span><span class="token number">4</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span> <span class="token comment">% 指定位置的元素都变为 100</span>

<span class="token comment">% 删除</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">% 删除 a 的第一个元素</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token keyword">end</span> <span class="token operator">-</span> <span class="token number">1</span><span class="token operator">:</span><span class="token keyword">end</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">% 删除 a 中最后两个元素</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="矩阵-1" tabindex="-1"><a class="header-anchor" href="#矩阵-1" aria-hidden="true">#</a> 矩阵</h3><h4 id="创建矩阵" tabindex="-1"><a class="header-anchor" href="#创建矩阵" aria-hidden="true">#</a> 创建矩阵</h4><p><strong>1. 直接输入法</strong></p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code><span class="token comment">% 同行元素用空格或者逗号分开，行与行之间用分号或者回车键分隔</span>
a <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span> <span class="token number">2</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token number">4</span> <span class="token number">5</span> <span class="token number">6</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>2. 函数创建法</strong></p><ul><li><code>zeros(m, [n])、ones(m, [n]) 和 eye(m, [n])</code>，分别用来创建 0 矩阵，1 矩阵和单位矩阵</li><li>关键词：随机数， <code>rand、randi 和 randn</code>，分别用来创建均匀分布的随机数、均匀分布的随机整数和标准正态分布的随机数 <ul><li>rand(m, [n]) 函数用来创建 0 和 1 内均匀分布的随机数</li><li>randi([imin, imax], m, [n])，可以创建一个 m 行 n 列的随机数矩阵，该随机数矩阵中的每个元素都是从 [imin, imax] 内随机抽取的整数 <ul><li>如果 imin = 1，即可简写为 rand(imax, m, n)</li></ul></li><li>randn(m, [n])</li></ul></li><li><code>diag 和 blkdiag</code><ul><li>diag 函数可用来创建对角矩阵或者获取矩阵的对角元素 <ul><li>如果第一个参数是向量，则表示创建对角矩阵 <ul><li>diag(v, k)，将向量 v 的元素放置在第 k 条对角线上，其他位置元素为 0。k = 0 表示主对角线，k &gt; 0 位于主对角线上方， k &lt; 0 位于主对角线下方。如果 k = 0，可以直接写成 diag(v)</li></ul></li><li>如果第一个参数是矩阵，则表示获取矩阵的对焦元素 <ul><li>diag(A, k)，返回 A 的第 k 条对角线上元素构成的<strong>列向量</strong>。k 的规则同上</li></ul></li></ul></li><li>blkdiag(A1, A2, ...) 函数可用来创建分块对角矩阵</li></ul></li></ul><p><strong>3. 导入本地文件中的数据</strong></p><p>MATLAB 可读取本地的文件，支持的常见格式如下：</p><ul><li>.txt、.dat 或 .csv（适用于带分隔符的文本文件）</li><li>.xls、.xlsb、.xlsm、.xltm、.xltx 或 .ods（适用于电子表格文件）</li></ul><p>重点关注 MATLAB “主页——导入数据”这个功能</p><h4 id="矩阵元素的引用" tabindex="-1"><a class="header-anchor" href="#矩阵元素的引用" aria-hidden="true">#</a> 矩阵元素的引用</h4><p><code>a(row_ind, col_ind)</code>，过于 row_ind, col_ind</p><ul><li>若都是常数，则表示提取矩阵中的单个元素</li><li>若是包含多个元素的向量，则表示同时提取多个位置上的元素</li></ul><p>与向量类似，end 也可以用来替代最后一个索引，常和冒号法一起使用</p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>a <span class="token operator">=</span> <span class="token function">randi</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token keyword">end</span><span class="token punctuation">)</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token operator">:</span><span class="token number">5</span><span class="token punctuation">)</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
<span class="token comment">% 奇数行且奇数列对应位置的元素</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token operator">:</span><span class="token number">2</span><span class="token operator">:</span><span class="token keyword">end</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token operator">:</span><span class="token number">2</span><span class="token operator">:</span><span class="token keyword">end</span><span class="token punctuation">)</span>
<span class="token comment">% a(:, n) 表示矩阵的第 n 列 的所有元素</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token operator">:</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token operator">:</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
<span class="token comment">% a(m, :) 表示矩阵第 m 行的所有元素</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token operator">:</span><span class="token punctuation">)</span>
<span class="token function">a</span><span class="token punctuation">(</span><span class="token keyword">end</span><span class="token punctuation">,</span> <span class="token operator">:</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>size</code> 函数：</p><ul><li>size(A) 返回一个行向量，其元素是 A 的各维度长度。若 A 是一个 3 x 4 的矩阵，则 size(A) 返回向量 [3 4]；如果让 [r, c] = size(A)，那么 r = 3，c = 4</li><li>size(A, dim) 返回在维度 dim 上的长度。 如：dim = 1, 表示行；dim = 2，表示列</li></ul><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>  A <span class="token operator">=</span> <span class="token function">ones</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span>
  <span class="token function">size</span><span class="token punctuation">(</span>A<span class="token punctuation">)</span>
  <span class="token punctuation">[</span>r<span class="token punctuation">,</span> c<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">size</span><span class="token punctuation">(</span>A<span class="token punctuation">)</span>
  r_mun <span class="token operator">=</span> <span class="token function">size</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>
  r_col <span class="token operator">=</span> <span class="token function">size</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="custom-container warning"><p class="custom-container-title">注意</p><p><code>length(A)</code> 会返回行和列中的较大值；<code>numel(A)</code> 会返回矩阵中元素的总数</p></div><p>前面都是对矩阵的双下标进行索引，事实上，在 MATLAB 中也能使用单个下标对矩阵进行索引，称为线性索引（矩阵按照各列顺次连接）</p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code><span class="token comment">% A(:) 可以将矩阵 A 中的所有元素按照线性索引的顺序重构成一个列向量</span>
A <span class="token operator">=</span> <span class="token function">randi</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token operator">:</span><span class="token punctuation">)</span>
<span class="token comment">% 同理对向量也有同样的效果（行 -&gt; 列）</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>sub2ind 和 ind2sub</code> 函数可用于在矩阵的原始索引和线性索引之间进行转换：</p><ul><li>ind = sub2ind(sz, row, col) 针对大小为 sz 的矩阵返回由 row 和 col 指定的行列下标的对应线性索引 ind。其中 sz 是包含两个向量的元素，sz(1) 是行数，sz(2) 是列数</li><li>[row, col] = ind2sub(sz, ind)</li></ul><h4 id="矩阵元素的修改和删除" tabindex="-1"><a class="header-anchor" href="#矩阵元素的修改和删除" aria-hidden="true">#</a> 矩阵元素的修改和删除</h4><p><strong>修改</strong></p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">:</span><span class="token number">4</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token operator">:</span><span class="token number">5</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token operator">:</span><span class="token number">6</span><span class="token punctuation">]</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">10</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token operator">:</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">100</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">8</span> <span class="token number">88</span><span class="token punctuation">;</span> <span class="token number">888</span> <span class="token number">8888</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="custom-container warning"><p class="custom-container-title">注意</p><p>如果在赋值时，将一个或多个元素置于矩阵现有的行和列索引的边界之外，则会将矩阵的大小进行拓展，没有赋值的位置自动用 0 填充，使其保持完整的矩形</p></div><p>此外可以通过在现有索引之外插入一个新的矩阵来拓展原始矩阵的大小</p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token number">30</span><span class="token punctuation">;</span>
    <span class="token number">60</span><span class="token punctuation">,</span> <span class="token number">70</span><span class="token punctuation">,</span> <span class="token number">80</span><span class="token punctuation">]</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token operator">:</span><span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">:</span><span class="token number">6</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">2</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token number">4</span> <span class="token number">5</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>删除</strong></p><p>将等号右侧变成空向量 <code>[]</code>，则可以删除对应位置的元素。需要注意的是，<strong>通常只能删除矩阵的整行或者整列，否则会报错</strong></p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">:</span><span class="token number">4</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token operator">:</span><span class="token number">5</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token operator">:</span><span class="token number">6</span><span class="token punctuation">]</span>
<span class="token comment">% 删除第一列</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token operator">:</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>

A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">:</span><span class="token number">4</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token operator">:</span><span class="token number">5</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token operator">:</span><span class="token number">6</span><span class="token punctuation">]</span>
<span class="token comment">% 删除第2， 最后列</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token operator">:</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token keyword">end</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意，也可以使用线性索引来删除矩阵元素。使用线性索引删除后，MATLAB 会将矩阵中剩下的元素按照线性索引的顺序放入到一个向量中。另外，使用线性索引可以删除任意位置的元素， 不需要删除矩阵的一整行或者一整列，但得到的是一个向量</p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">:</span><span class="token number">4</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token operator">:</span><span class="token number">5</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token operator">:</span><span class="token number">6</span><span class="token punctuation">]</span>
<span class="token function">A</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token operator">:</span><span class="token number">4</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="矩阵的拼接和重复" tabindex="-1"><a class="header-anchor" href="#矩阵的拼接和重复" aria-hidden="true">#</a> 矩阵的拼接和重复</h4><p><strong>拼接</strong></p><p><img src="`+t+'" alt="矩阵拼接" title="矩阵拼接"></p><p>横向拼接：</p><ul><li>[A, B, ...]</li><li>[A B ...]</li><li>horzcat(A, B, ...)</li></ul><p>纵向拼接：</p><ul><li>[A; B; ...]，或者用换行符隔开</li><li>vertcat(A, B, ...)</li></ul><p><code>cat(dim, A, B, ...)</code> 函数表示沿着维度 dim 方向将矩阵 B 拼接到矩阵 A 的末尾</p><ul><li>dim = 1，即纵向拼接</li><li>dim = 2，即横向拼接</li></ul><p><strong>重复</strong></p><p><img src="'+o+`" alt="repmat" title="repmat"></p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code><span class="token comment">% 对矩阵重复</span>
A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span>
B <span class="token operator">=</span> <span class="token function">repmat</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>除了对整个矩阵进行重复的堆叠外，MATLAB 还可以对向量或矩阵中的元素进行重复，使用 <code>repelem</code> 函数：</p><ul><li><code>repelem(v, n)</code>，重复向量 v 中的元素 <ul><li>当 n 为一个正整数时，表示把 v 中的每一个元素都重复 n 次；n 也可以为一个向量，其长度必须和 v 相同，它可以将 v(i) 重复 n(i) 次</li></ul><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>v <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">5</span> <span class="token number">3</span> <span class="token number">8</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
ans1 <span class="token operator">=</span> <span class="token function">repelem</span><span class="token punctuation">(</span>v<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token comment">% [5 5 3 3 8 8]</span>
ans2 <span class="token operator">=</span> <span class="token function">repelem</span><span class="token punctuation">(</span>v<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">% [5 5 3 8 8 8 8]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><code>repelem(A, m, n)</code>，重复矩阵 A 中的元素 <ul><li>m 和 n 分别表示沿着行方向（从上至下）以及沿着列方向（从左至右）将矩阵元素重复的次数，同理可以是整数或者向量</li></ul><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">;</span>
      <span class="token number">8</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">]</span>
<span class="token comment">% 针对 A 中的每个元素，沿着行方向重复 3 次，沿着列方向重复 2 次</span>
B <span class="token operator">=</span> <span class="token function">repelem</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
<span class="token comment">% 针对 A 中的每个元素，第一行重复两次，第二行重复 3 次；第一列重复 1 次，第二列重复 2 次，第三列重复 3 次</span>
C <span class="token operator">=</span> <span class="token function">repelem</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h4 id="矩阵的重构和重新排列" tabindex="-1"><a class="header-anchor" href="#矩阵的重构和重新排列" aria-hidden="true">#</a> 矩阵的重构和重新排列</h4><p><img src="`+c+`" alt="rebuild" title="rebuild"></p><h5 id="reshape" tabindex="-1"><a class="header-anchor" href="#reshape" aria-hidden="true">#</a> reshape</h5><p><code>reshape(A, m, n)</code> 或者 <code>reshape(A, [m, n])</code> 可将矩阵 A 的改为 m 行 n 列（按照线性索引的顺序），前提是转换前后的两个矩阵的元素总数相同</p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token function">randi</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">)</span>
B <span class="token operator">=</span> <span class="token function">reshape</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span>
<span class="token comment">% A(:) 与 B(:) 相同</span>
<span class="token comment">% 用 [] 代替转换后的列数或者行数，MATLAB 会对它进行计算</span>
B1 <span class="token operator">=</span> <span class="token function">reshape</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
B2 <span class="token operator">=</span> <span class="token function">reshape</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="sort" tabindex="-1"><a class="header-anchor" href="#sort" aria-hidden="true">#</a> sort</h5><p><strong>对向量排序</strong></p><p>假设 v 是一个向量，有下面两种基础用法：</p><ul><li><code>sort(v)</code>，升序排列</li><li><code>sort(v, &#39;descend&#39;)</code>，降序排序</li></ul><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>v <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">10</span> <span class="token number">24</span> <span class="token number">16</span> <span class="token number">8</span> <span class="token number">50</span> <span class="token number">40</span><span class="token punctuation">]</span>
r1 <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>v<span class="token punctuation">)</span>
r2 <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>v<span class="token punctuation">,</span> <span class="token string">&#39;descend&#39;</span><span class="token punctuation">)</span>
<span class="token comment">% 事实上，sort 返回了两个参数</span>
<span class="token punctuation">[</span>sort_v<span class="token punctuation">,</span> ind<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>v<span class="token punctuation">)</span> <span class="token comment">% sort_v 与 v(ind) 相同</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>对矩阵排序</strong></p><p><code>sort(A, dim)</code>：</p><ul><li>dim = 1，沿着行方向（从上至下）对矩阵的每一列升序排列</li><li>dim = 2，沿着列方向（从左至右）对矩阵的每一行升序排列</li></ul><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token function">randi</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">)</span>
<span class="token comment">% 升序</span>
B1 <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>A<span class="token punctuation">)</span>
B2 <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>
B3 <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
<span class="token comment">% 降序</span>
C1 <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;descend&#39;</span><span class="token punctuation">)</span>
C2 <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;descend&#39;</span><span class="token punctuation">)</span>
<span class="token comment">% 同理，也有两个返回值</span>
<span class="token punctuation">[</span>sort_A<span class="token punctuation">,</span> ind<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">sort</span><span class="token punctuation">(</span>A<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="sortrows" tabindex="-1"><a class="header-anchor" href="#sortrows" aria-hidden="true">#</a> sortrows</h5><p>默认升序</p><p><code>sortrows(矩阵, [参与排序的列-整数或者向量], [每一列排序的方向-两列eg： {&#39;ascend&#39;, &#39;descend&#39;}])</code> 函数基于矩阵的某一列对矩阵进行排序，排序后得到的新矩阵同一行不会改变</p><p><code>sortrows(score) 等价于 sortrows(score, 1:size(score, 2))</code></p><p><code>[sort_score, ind] = sortrows(score, 1)</code>，其中 ind 表示当前行在原矩阵中的行数，sort_score 与 score(ind, 😃 结果相同</p><h5 id="flip-fliplr-flipud" tabindex="-1"><a class="header-anchor" href="#flip-fliplr-flipud" aria-hidden="true">#</a> flip / fliplr / flipud</h5><p><strong>flip</strong></p><ul><li><code>flip(v)</code>，翻转向量中各个元素的顺序，向量的方向不变</li><li><code>flip(A, [dim = 1])</code>，对矩阵进行上下（dim = 1）、左右翻转（dim = 2）</li></ul><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>v <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">5</span> <span class="token number">2</span> <span class="token number">7</span> <span class="token number">8</span> <span class="token number">9</span><span class="token punctuation">]</span>
r1 <span class="token operator">=</span>  <span class="token function">flip</span><span class="token punctuation">(</span>v<span class="token punctuation">)</span> <span class="token comment">% [9 8 7 2 5]</span>
r <span class="token operator">=</span> <span class="token function">flip</span><span class="token punctuation">(</span>v<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">% 不变，上下翻转</span>

A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">5</span> <span class="token number">8</span> <span class="token number">7</span><span class="token punctuation">;</span>
    <span class="token number">4</span> <span class="token number">2</span> <span class="token number">6</span><span class="token punctuation">;</span>
    <span class="token number">3</span> <span class="token number">5</span> <span class="token number">8</span><span class="token punctuation">;</span>
    <span class="token number">6</span> <span class="token number">4</span> <span class="token number">1</span><span class="token punctuation">]</span>
r2 <span class="token operator">=</span> <span class="token function">flip</span><span class="token punctuation">(</span>A<span class="token punctuation">)</span> <span class="token comment">% 对每一列进行翻转，前后对应行不会变</span>
r3 <span class="token operator">=</span> <span class="token function">flip</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token comment">% 对每一行进行翻转，前后对应列不会变</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="rot90" tabindex="-1"><a class="header-anchor" href="#rot90" aria-hidden="true">#</a> rot90</h5><p>rotate 旋转</p><p><code>rot90(A, k)</code>，将矩阵 A 沿着逆时针方向旋转 k * 90°，其中 k 是一个整数，默认为 1</p><div class="language-matlab line-numbers-mode" data-ext="matlab"><pre class="language-matlab"><code>A <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">5</span> <span class="token number">8</span> <span class="token number">7</span><span class="token punctuation">;</span>
    <span class="token number">4</span> <span class="token number">2</span> <span class="token number">6</span><span class="token punctuation">;</span>
    <span class="token number">3</span> <span class="token number">5</span> <span class="token number">8</span><span class="token punctuation">;</span>
    <span class="token number">6</span> <span class="token number">4</span> <span class="token number">1</span><span class="token punctuation">]</span>
B1 <span class="token operator">=</span> <span class="token function">rot90</span><span class="token punctuation">(</span>A<span class="token punctuation">)</span>
B2 <span class="token operator">=</span> <span class="token function">rot90</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
<span class="token comment">% 下面两个结果等价</span>
B3 <span class="token operator">=</span> <span class="token function">rot90</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>
B4 <span class="token operator">=</span> <span class="token function">rot90</span><span class="token punctuation">(</span>A<span class="token punctuation">,</span> <span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,110)]))}const k=s(l,[["render",i],["__file","index.html.vue"]]);export{k as default};
